{
    "level": "A2",
    "intro": "У цій темі ти навчишся вживати <strong>some people, any people, no people</strong> і близькі займенникові форми без типових помилок.",
    "rules": [
        {
            "label": "STVERDZHENNIA",
            "color": "emerald",
            "text": "<strong>Some people</strong> найчастіше вживаємо у ствердженнях:",
            "example": "Some people work better at night."
        },
        {
            "label": "PYTANNIA / ZAPERECHENNIA",
            "color": "blue",
            "text": "<strong>Any people</strong> типово з’являється в питаннях і запереченнях:",
            "example": "Do you know any people here?"
        },
        {
            "label": "NEGATIVE IDEA",
            "color": "rose",
            "text": "<strong>No people</strong> або <strong>nobody / no one</strong> уже містять заперечення:",
            "example": "No people were waiting outside."
        }
    ]
}

{
    "title": "1. Основні форми",
    "intro": "Порівняй найуживаніші моделі з іменником <strong>people</strong> та спорідненими займенниками.",
    "items": [
        {
            "label": "Ствердження",
            "title": "some people",
            "subtitle": "деякі люди: Some people need more time."
        },
        {
            "label": "Питання / заперечення",
            "title": "any people",
            "subtitle": "Do you know any people there?"
        },
        {
            "label": "Повне заперечення",
            "title": "no people",
            "subtitle": "No people came to the meeting."
        },
        {
            "label": "Займенник",
            "title": "someone / anyone / no one",
            "subtitle": "Someone is at the door."
        }
    ]
}

{
    "title": "2. Як це працює в реченнях",
    "sections": [
        {
            "label": "Ствердження з some people",
            "color": "emerald",
            "description": "<strong>Some people</strong> природно звучить, коли ти говориш про невизначену частину групи.",
            "examples": [
                {
                    "en": "Some people learn faster with examples.",
                    "ua": "Деякі люди вчаться швидше на прикладах."
                },
                {
                    "en": "Some people in my class already have jobs.",
                    "ua": "Деякі люди в моїй групі вже мають роботу."
                },
                {
                    "en": "Some people just prefer quiet cafés.",
                    "ua": "Деякі люди просто надають перевагу тихим кав’ярням."
                }
            ]
        },
        {
            "label": "Питання і заперечення з any people",
            "color": "blue",
            "description": "У нейтральних питаннях і запереченнях частіше використовуємо <strong>any people</strong>.",
            "examples": [
                {
                    "en": "Do you know any people in Warsaw?",
                    "ua": "Ти знаєш когось у Варшаві?"
                },
                {
                    "en": "I do not know any people on this street.",
                    "ua": "Я не знаю нікого на цій вулиці."
                },
                {
                    "en": "Are there any people in the office now?",
                    "ua": "У офісі зараз є люди?"
                }
            ],
            "note": "Якщо ти очікуєш позитивну відповідь, у питанні може з’явитися <strong>some people</strong>."
        },
        {
            "label": "No people і займенникові форми",
            "color": "rose",
            "description": "<strong>No people</strong>, <strong>nobody</strong> і <strong>no one</strong> самі по собі вже негативні.",
            "examples": [
                {
                    "en": "No people were sitting outside.",
                    "ua": "Надворі не сиділо жодних людей."
                },
                {
                    "en": "Nobody answered the phone.",
                    "ua": "Ніхто не відповів на телефон."
                },
                {
                    "en": "No one wanted to leave early.",
                    "ua": "Ніхто не хотів іти раніше."
                }
            ],
            "note": "Не додавай ще одне <strong>not</strong>: не <span class=\"line-through\">I do not know nobody</span>."
        }
    ]
}

{
    "title": "3. Типові помилки",
    "items": [
        {
            "label": "Помилка 1",
            "color": "rose",
            "title": "Some у нейтральному питанні.",
            "wrong": "Do you know some people here?",
            "right": "✅ <span class=\"font-mono\">Do you know any people here?</span>"
        },
        {
            "label": "Помилка 2",
            "color": "amber",
            "title": "Подвійне заперечення.",
            "wrong": "I do not know no people there.",
            "right": "✅ <span class=\"font-mono\">I do not know any people there.</span> / <span class=\"font-mono\">I know no people there.</span>"
        },
        {
            "label": "Помилка 3",
            "color": "sky",
            "title": "Неправильне узгодження з people.",
            "wrong": "Some people is waiting outside.",
            "right": "✅ <span class=\"font-mono\">Some people are waiting outside.</span>"
        }
    ]
}

{
    "title": "4. Короткий конспект",
    "items": [
        "<strong>Some people</strong> — звичайний вибір для стверджень.",
        "<strong>Any people</strong> — типовий вибір для питань і заперечень.",
        "<strong>No people</strong>, <strong>nobody</strong>, <strong>no one</strong> уже містять негативне значення.",
        "Після <strong>people</strong> дієслово зазвичай стоїть у множині: <em>people are</em>.",
        "Уникай подвійного заперечення: <em>I do not know anybody</em> або <em>I know nobody</em>."
    ]
}

{
    "title": "Сторінки цього розділу",
    "items": [
        {
            "label": "Some / Any — Places",
            "url": "/theory/some-any/theory-some-any-places",
            "current": false
        },
        {
            "label": "Some / Any — People",
            "url": "/theory/some-any/theory-some-any-people",
            "current": true
        },
        {
            "label": "Some / Any — Things",
            "url": "/theory/some-any/theory-some-any-things",
            "current": false
        }
    ]
}
